import { pool } from '../config/database';
import { User, UserRole } from '../models/types';

export class UserRepository {
  async findAll(): Promise<User[]> {
    const result = await pool.query(
      'SELECT id, name, email, role, created_at AS "createdAt", updated_at AS "updatedAt" FROM users ORDER BY name ASC',
    );
    return result.rows;
  }

  async findById(id: string): Promise<User | null> {
    const result = await pool.query(
      'SELECT id, name, email, role, created_at AS "createdAt", updated_at AS "updatedAt" FROM users WHERE id = $1',
      [id],
    );
    return result.rows[0] || null;
  }

  async findByEmail(email: string): Promise<User | null> {
    const result = await pool.query(
      'SELECT id, name, email, role, created_at AS "createdAt", updated_at AS "updatedAt" FROM users WHERE email = $1',
      [email],
    );
    return result.rows[0] || null;
  }

  async create(name: string, email: string, passwordHash: string, role: UserRole): Promise<User> {
    const result = await pool.query(
      `INSERT INTO users (name, email, password_hash, role)
       VALUES ($1, $2, $3, $4)
       RETURNING id, name, email, role, created_at AS "createdAt", updated_at AS "updatedAt"`,
      [name, email, passwordHash, role],
    );
    return result.rows[0];
  }

  async update(id: string, fields: { name?: string; email?: string; role?: UserRole; passwordHash?: string }): Promise<User | null> {
    const setClauses: string[] = [];
    const params: unknown[] = [];
    let paramIndex = 1;

    if (fields.name !== undefined) {
      setClauses.push(`name = $${paramIndex++}`);
      params.push(fields.name);
    }
    if (fields.email !== undefined) {
      setClauses.push(`email = $${paramIndex++}`);
      params.push(fields.email);
    }
    if (fields.role !== undefined) {
      setClauses.push(`role = $${paramIndex++}`);
      params.push(fields.role);
    }
    if (fields.passwordHash !== undefined) {
      setClauses.push(`password_hash = $${paramIndex++}`);
      params.push(fields.passwordHash);
    }

    if (setClauses.length === 0) return this.findById(id);

    setClauses.push(`updated_at = NOW()`);
    params.push(id);

    const result = await pool.query(
      `UPDATE users SET ${setClauses.join(', ')}
       WHERE id = $${paramIndex}
       RETURNING id, name, email, role, created_at AS "createdAt", updated_at AS "updatedAt"`,
      params,
    );
    return result.rows[0] || null;
  }

  async delete(id: string): Promise<boolean> {
    const result = await pool.query('DELETE FROM users WHERE id = $1', [id]);
    return (result.rowCount ?? 0) > 0;
  }
}

