import bcrypt from 'bcryptjs';
import { UserRepository } from '../repositories/user.repository';
import { User, CreateUserDto, AdminUpdateUserDto } from '../models/types';
import { AppError } from '../middleware/error-handler';

export class UserService {
  private userRepository: UserRepository;

  constructor(userRepository?: UserRepository) {
    this.userRepository = userRepository || new UserRepository();
  }

  async getAllUsers(): Promise<User[]> {
    return this.userRepository.findAll();
  }

  async getUserById(id: string): Promise<User> {
    const user = await this.userRepository.findById(id);
    if (!user) {
      throw new AppError(404, 'User not found');
    }
    return user;
  }

  async createUser(dto: CreateUserDto): Promise<User> {
    const existing = await this.userRepository.findByEmail(dto.email);
    if (existing) {
      throw new AppError(400, 'Email is already in use', 'email');
    }

    if (!dto.password || dto.password.length < 6) {
      throw new AppError(400, 'Password must be at least 6 characters', 'password');
    }

    const passwordHash = await bcrypt.hash(dto.password, 12);
    return this.userRepository.create(dto.name, dto.email, passwordHash, dto.role);
  }

  async updateUser(id: string, dto: AdminUpdateUserDto): Promise<User> {
    const user = await this.userRepository.findById(id);
    if (!user) {
      throw new AppError(404, 'User not found');
    }

    if (dto.email && dto.email !== user.email) {
      const existing = await this.userRepository.findByEmail(dto.email);
      if (existing) {
        throw new AppError(400, 'Email is already in use', 'email');
      }
    }

    let passwordHash: string | undefined;
    if (dto.password) {
      if (dto.password.length < 6) {
        throw new AppError(400, 'Password must be at least 6 characters', 'password');
      }
      passwordHash = await bcrypt.hash(dto.password, 12);
    }

    const updated = await this.userRepository.update(id, {
      name: dto.name,
      email: dto.email,
      role: dto.role,
      passwordHash,
    });

    if (!updated) {
      throw new AppError(404, 'User not found');
    }

    return updated;
  }

  async deleteUser(id: string): Promise<void> {
    const deleted = await this.userRepository.delete(id);
    if (!deleted) {
      throw new AppError(404, 'User not found');
    }
  }
}

