                </td>
                <td>{role.description || '—'}</td>
                <td className="roles-page__permissions">
                  {role.name === 'admin' && 'Full access — manage users, roles, tickets'}
                  {role.name === 'user' && 'Create, edit tickets, change status, add comments'}
                  {role.name === 'agent' && 'View-only — dashboard, tickets, kanban'}
